class NotificationFactory {
    static Notification create(String type) {
        if (type.equals("email")) {
            SmtpConfig c = loadSmtpConfig(); // email's private knowledge
            return new EmailNotification(c);
        } else if (type.equals("sms")) {
            SmsApiKey k = loadApiKey(); // sms's private knowledge
            return new SMSNotification(k);
        }
    }
}

goodCode:
// Products self-configure (Simple Factory stays clean)
class EmailNotification implements Notification {
    public EmailNotification() {
        this.config = SmtpConfig.load(); // I load my own config
    }
}
// OR use Factory Method when creation is genuinely complex
class EmailNotificationService extends NotificationService {
    Notification createNotification() {
        SmtpConfig config = loadSmtpConfig(); // my private knowledge
        return new EmailNotification(config);
    }
}

// Use enums -- typos caught at COMPILE time
enum NotificationType { EMAIL, SMS, PUSH }
Notification n = factory.create(NotificationType.EMAIL); // safe

